struct Tag {
    Tag() :add(0) {}
    Tag(ll add) : is_init(0), add(add) {}

    bool is_init = 1; // 初始化时不用 tag

    // 距离变化
    ll add;
    void apply(const Tag& t) {
        // 父tag怎么传到子tag
        if (not t.is_init) {
            is_init = 0;
            add += t.add;
        }
    }
};
struct Info {
    Info() :dis(1e9), st(1e9), val(1e9) {};
    Info(ll dis, ll st, ll val) :dis(dis), st(st), val(val) {};

    // 距离、激活态(1/1e9)、真实距离
    ll dis, st, val;
    void apply(const Tag& t, int len) {
        // tag怎么传到要维护的值
        if (not t.is_init) {
            dis += t.add;
            val = st * dis;
        }
    }

    void apply(const Info& v) {
        // 如何单点修改
        if (st == 1e9)st = 1;
        else st = 1e9;
        val = dis * st;
    }
};
Info operator+(const Info& a, const Info& b) {
    Info c;
    c.val = min(a.val, b.val);
    c.dis = 1e9;
    if (a.st == 1)c.dis = min(c.dis, a.dis);
    if (b.st == 1)c.dis = min(c.dis, b.dis);
    c.st = min(a.st, b.st);
    return c;
}

void solve()
{
    int n, m; cin >> n >> m;
    var g = vector<vector<int>>(n + 1);
    fa(i, 1, n - 1) {
        int u, v; cin >> u >> v;
        g[u].pb(v), g[v].pb(u);
    }
    int timer = 0;
    var in = vector<int>(n + 1);
    var out = vector<int>(n + 1);
    var rnk = vector<int>(n + 1);
    var dep = vector<ll>(n + 1);
    var dfs = [&](var dfs, int now, int fa)->void {
        in[now] = ++timer;
        rnk[timer] = now;
        for (int to : g[now]) {
            if (to == fa)continue;
            dfs(dfs, to, now);
        }
        out[now] = timer;
    };
    var dfss = [&](var dfs, int now, int fa)->void {
        dep[now] = dep[fa] + 1;
        for (int to : g[now]) {
            if (to == fa)continue;
            dfs(dfs, to, now);
        }
    };
    dfs(dfs, 1, 0);
    dfss(dfss, 1, 0);
    var _init = vector<Info>(n + 1);
    fa(i, 1, n)_init[in[i]] = { dep[i],(ll)1e9,dep[i] * (ll)1e9 };
    var t = LazySegmentTree<Info, Tag>(_init);
    int now = 1;
    while (m--) {
        int op; cin >> op;
        int to; cin >> to;
        if (op == 1)t.modify(in[to], { 0,1,0 });
        else {
            if (dep[to] > dep[now]) {
                t.modifyRange(1, n, 1);
                t.modifyRange(in[to], out[to], -2);
            }
            else {
                t.modifyRange(1, n, -1);
                t.modifyRange(in[now], out[now], 2);
            }
            now = to;
        }
        ll ans = t.query(1, n).val;
        if (ans >= 1e9)cout << 2147483648 << endl;
        else cout << ans - 1 << endl;
    }
    return;
}
